css:
@page { size: A4; margin: 1.8cm 1.5cm 2cm 1.5cm; }
body { font-family: 'Times New Roman', serif; font-size: 11.5pt; color: #1a1a1a; line-height: 1.6; }
.kya-pdf-page { padding: 0; }
.kya-header { width: 100%; border-collapse: collapse; }
.kya-header td { vertical-align: middle; padding: 0; }
.kya-header .kya-logo { width: 110px; }
.kya-header .kya-logo img { max-width: 100px; max-height: 80px; }
.kya-header .kya-title { padding-left: 15px; }
.kya-header h1 { margin: 0; color: #e07b00; font-size: 20pt; letter-spacing: 1px; }
.kya-header p { margin: 2px 0; font-size: 9pt; color: #555; }
.kya-bar { height: 4px; background: linear-gradient(to right, #f7a800 0%, #e07b00 60%, #1a5276 100%); margin: 8px 0 18px 0; border-radius: 2px; }
.kya-ref table { width: 100%; font-size: 10pt; color: #444; }
.kya-doc-title { text-align: center; color: #1a5276; font-size: 16pt; margin: 20px 0 16px 0; padding-bottom: 6px; border-bottom: 2px solid #f7a800; letter-spacing: 1px; }
.kya-corps { text-align: justify; font-size: 11.5pt; }
.kya-corps h2, .kya-corps h3 { color: #e07b00; font-size: 12.5pt; margin-top: 16px; margin-bottom: 6px; }
.kya-corps p { margin: 6px 0; }
.kya-corps strong, .kya-corps b { color: #1a5276; }
.kya-mention { margin: 30px 0 14px 0; text-align: center; }
.kya-signatures { width: 100%; margin-top: 14px; border-collapse: collapse; page-break-inside: avoid; }
.kya-signatures .sig-cell { width: 50%; vertical-align: top; padding: 14px 18px; border: 1px solid #ddd; text-align: center; height: 170px; }
.sig-titre { font-weight: bold; color: #1a5276; font-size: 12pt; margin-bottom: 4px; }
.sig-mention { font-style: italic; color: #888; font-size: 9.5pt; margin-bottom: 8px; }
.sig-img-wrap { height: 90px; margin: 4px 0; }
.sig-img { max-height: 80px; max-width: 200px; }
.sig-name { font-weight: bold; margin-top: 6px; font-size: 11pt; }
.sig-date { color: #666; font-size: 9pt; margin-top: 2px; }
.kya-footer-pdf { margin-top: 25px; text-align: center; font-size: 9pt; color: #666; }
.kya-footer-pdf hr { border: 0; border-top: 1px solid #ddd; }
